#include<bits/stdc++.h>
using namespace std;
long long n,m,a,b,c;
long long dis[4][1010][1010],r[1010][1010];
struct node
{
    long long x,y,dis;
    bool operator<(const node&b)const
    {
        return dis>b.dis;
    }
};
bool vis[1010][1010];
int dx[4]={0,-1,0,1};
int dy[4]={1,0,-1,0};
void bfs(long long x,long long y,long long k)
{
    priority_queue<node> q;
    q.push((node){x,y,r[x][y]});
    memset(dis[k],0x3f,sizeof(dis[k]));
    memset(vis,0,sizeof(vis));
    dis[k][x][y]=r[x][y];
    while(!q.empty())
    {
        node t=q.top();
        q.pop();
        if(vis[t.x][t.y])
        {
            continue;
        }
        vis[t.x][t.y]=1;
        for(int i=0;i<4;i++)
        {
            node t1;
            t1.x=t.x+dx[i];
            t1.y=t.y+dy[i];
            if(t1.x<1||t1.x>n||t1.y<1||t1.y>m)
            {
                continue;
            }
            t1.dis=t.dis+r[t1.x][t1.y];
            if(dis[k][t1.x][t1.y]>t1.dis)
            {
                dis[k][t1.x][t1.y]=t1.dis;
                q.push(t1);
            }
        }
    }
}
int main()
{
    scanf("%lld%lld%lld%lld%lld",&n,&m,&a,&b,&c);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%d",&r[i][j]);
        }
    }
    bfs(1,a,1);
    bfs(n,b,2);
    bfs(n,c,3);
    long long ans=LLONG_MAX;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            ans=min(ans,dis[1][i][j]+dis[2][i][j]+dis[3][i][j]-r[i][j]*2);
        }
    }
    printf("%lld",ans);
    return 0;
}
